// src/app/api/auth/set-password/route.ts
//
// POST /api/auth/set-password
//
// Used by invited team members to set their password using the token from
// their invitation email. The token was generated by POST /api/team and
// stored as User.resetToken (hashed).
//
// Request body: { token: string, password: string }
// On success: password is set, resetToken cleared, 200 OK.

import { NextRequest, NextResponse } from "next/server";
import { detectCapabilities } from '@arkiol/shared';
import { prisma }            from "../../../../lib/prisma";
import { hashPassword, validatePasswordStrength } from "../../../../lib/auth";
import { withErrorHandling, dbUnavailable } from "../../../../lib/error-handling";
import { rateLimit }         from "../../../../lib/rate-limit";
import { ApiError }          from "../../../../lib/types";
import { z }                 from "zod";

const SetPasswordSchema = z.object({
  token:    z.string().min(64).max(64),
  password: z.string().min(8).max(128),
});

export const POST = withErrorHandling(async (req: NextRequest) => {
  if (!detectCapabilities().database) return dbUnavailable();

  const ip = req.headers.get("x-forwarded-for") ?? "unknown";
  const rl = await rateLimit(ip, "auth");
  if (!rl.success) {
    return NextResponse.json({ error: "Too many attempts. Please wait." }, { status: 429 });
  }

  const body   = await req.json().catch(() => ({}));
  const parsed = SetPasswordSchema.safeParse(body);
  if (!parsed.success) {
    return NextResponse.json(
      { error: "Invalid request", details: parsed.error.flatten() },
      { status: 400 }
    );
  }

  const { token, password } = parsed.data;

  // Validate password strength
  const pwError = validatePasswordStrength(password);
  if (pwError) {
    return NextResponse.json({ error: pwError }, { status: 400 });
  }

  // Find the user by reset token
  const user = await prisma.user.findFirst({
    where: { resetToken: token },
    select: { id: true, email: true, resetToken: true, resetTokenExpiry: true },
  });

  // Use constant-time path regardless of whether user exists
  if (!user || !user.resetToken) {
    throw new ApiError(400, "Invalid or expired invitation token");
  }

  if (user.resetTokenExpiry && user.resetTokenExpiry < new Date()) {
    throw new ApiError(400, "Invitation link has expired. Ask your admin to re-send the invite.");
  }

  const passwordHash = await hashPassword(password);

  await prisma.user.update({
    where: { id: user.id },
    data: {
      passwordHash,
      resetToken:        null,
      resetTokenExpiry:  null,
    },
  });

  return NextResponse.json({
    success: true,
    message: "Password set successfully. You can now sign in.",
    email:   user.email,
  });
});
